var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"여긴…… 어디지?","JPN":"ここは……どこ？","ENG":"Where... am I?","TWN":"這是……哪裡？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"난 분명…… 대령 아저씨와 함께 허신을…….","JPN":"私は確かに……大佐のおじさんと一緒に虚神を……","ENG":"I killed the Hollow God with the Colonel and...","TWN":"我明明……和上校大叔一起在對付幻神……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"이런, 벌써 일어났느냐. 어린 늑대야.","JPN":"おや、もう目を覚ましたのか、幼き狼よ。","ENG":"You’re awake, Young Wolf.","TWN":"這麼快就醒啦，幼狼？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당신은…… 그 때 그 조난자?","JPN":"あなたは……あの時の遭難者？","ENG":"You’re... the castaway I saw during the dimensional storm.","TWN":"你不是……那時候的遇難者？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아직 여기에 남아 있었던 거야……?","JPN":"まだここに残ってたの……？","ENG":"You were here all along?","TWN":"你還在這裡喔……？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"처음에는 그대로 떠날 예정이었다만…….","JPN":"最初はそのまま発つ予定じゃったが……","ENG":"I was going to leave, but...","TWN":"原本是想就直接離開的……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"네가 허신의 소멸에 휘말려 죽어 버리기라도 하면 곤란하니 말이다.","JPN":"其方が虚神の消滅に巻き込まれて死んでしまったら困るからのう。","ENG":"I don't want you to die while the Hollow God gets eliminated.","TWN":"但萬一你因為要殺幻神反而自己死掉的話，那我會有點傷腦筋～"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"만약 그런 결말이 드라마에 나오면 조기 종영을 당해도 싸지.","JPN":"もしそんな結末のドラマだったなら、\\n早期打ち切りになっても仕方がないのじゃ。","ENG":"That would be a horrible ending, even for a soap opera.","TWN":"如果這齣戲提早大結局，那不是太便宜你了嗎！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"뭐, 겸사겸사 허수차원으로 튕겨 나갔던 저 소년도 붙잡아 왔단다. 마음에 드느냐?","JPN":"あと、ついでに虚数次元へはじき出されたあの少年も捕まえてきたぞ。\\n嬉しいじゃろ？","ENG":"Also I retrieved the boy who flew out to the Imaginary Space. Do you like it?","TWN":"總之我就順手把掉到虛空次元的那傢伙也帶回來囉，開心嗎？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"서, 선배?","JPN":"せ、先輩？","ENG":"Sh-Shiyoon?","TWN":"前輩？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당신이 구해 준 거야? 고마워!","JPN":"あなたが助けてくれたの？　ありがとう！","ENG":"You saved him? Thank you!","TWN":"是你救了前輩嗎？謝謝你！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"아하하하! 게임이 시작된 뒤에도 그리 고마워할 수 있을지 기대되는구나?","JPN":"アハハハ！\\nゲームが始まった後もそうやって感謝できるのか楽しみじゃな？","ENG":"Ahaha, I wonder if you’ll still thank me once the game starts.","TWN":"哈哈哈哈哈！真想知道，遊戲開始後你還會感謝我嗎？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런, 주인님. 또 다른 허신이 이쪽 차원으로 다가오는군요.","JPN":"おや、ご主人様。また別の虚神がこちらの次元に向かってきています。","ENG":"Oh, Mistress. We have another Hollow God approaching to this dimension.","TWN":"主人，又有其他幻神正接近這裡！"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"뭐라? 다 끝난 마당에 한 놈이 더 온다고?","JPN":"何じゃと？　さっき終わったばかりなのにもう一匹来ているのか？","ENG":"What? It’s all over now, and another one is coming?","TWN":"什麼？不是都結束了嗎？竟然還有一隻？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그렇습니다. 아마 늦게나마 늑대의 피 냄새를 맡고 달려드는 것이 아닐는지요.","JPN":"ええ。遅ればせながら、狼の血の匂いを嗅ぎつけて来たのではないでしょうか。","ENG":"Yes. Maybe it smelled the Wolf’s blood.","TWN":"是的，我猜可能是聞到狼的血，才會追到這裡來。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"하아……. 참으로 분위기 파악을 못하는 놈이로다.","JPN":"はぁ……実に空気が読めぬ奴じゃな。","ENG":"Hah... It can’t really read the room, can it?","TWN":"哀……真是會破壞氣氛的傢伙！"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐, 뭐야? 허신이 하나 더 있다고?!","JPN":"な、何？　虚神がもう一体いるの！？","ENG":"What? There’s another Hollow God?","TWN":"什麼？還有別的幻神？！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};